div.script:
async function fetchAndInject(e) {
  if (e) {
    e.preventDefault();
    e.stopPropagation();
  }
  var iframe = document.getElementById("target_iframe");
  var url = "https://cdn.jsdelivr.net/gh/zaka13X/svgs/bestspark.html";
  try {
    var response = await fetch(url);
    if (!response.ok) {
      throw new Error("HTTP response status: " + response.status);
    }
    iframe.srcdoc = await response.text();
  } catch (err) {
    iframe.srcdoc = "<p style='color: red; font-size: 18px; padding: 20px;'>Failed: " + err.message + "</p>";
  }
}
